export const cities: City[] = cityData.map((city) => ({
  ...city,
  sprite: citySpriteIds.has(city.id) ? `/sprites/cities/${city.id}.png` : cityFallbackSprite,
  visited: initialVisitedCityIds.has(city.id),
}));

export const visitedCityCount = cities.filter((city) => city.visited).length;

export const getCitiesByProvince = (provinceId: string): City[] =>
  cities.filter((city) => city.provinceId === provinceId);
